          const relLinks = relSlugs.map(s=>T[s]?`<a href="${SITE_URL}/${tLang}/tarot/${s}/">${esc(T[s].name)}</a>`:'').join('');
          const faq=(TL.faq||[]).map(f=>({q:f.q.replace(/\{card\}/g,card.name),a:f.a.replace(/\{card\}/g,card.name)}));
          const faqHtml=faq.map(f=>`<details class="faq-item"><summary>${esc(f.q)}</summary><div class="faq-a">${esc(f.a)}</div></details>`).join('');
          const faqSchema=JSON.stringify({"@context":"https://schema.org","@type":"FAQPage","mainEntity":faq.map(f=>({'@type':'Question','name':f.q,'acceptedAnswer':{'@type':'Answer','text':f.a}}))});
          const bcSchema=JSON.stringify({"@context":"https://schema.org","@type":"BreadcrumbList","itemListElement":[{"@type":"ListItem","position":1,"name":LANGS[tLang].h1,"item":`${SITE_URL}/${tLang==='ko'?'':tLang+'/'}lucky/`},{"@type":"ListItem","position":2,"name":TL.title,"item":`${SITE_URL}/${tLang}/tarot/${tSlug}/`},{"@type":"ListItem","position":3,"name":card.name}]});
          const artSchema=JSON.stringify({"@context":"https://schema.org","@type":"Article","headline":cTitle,"inLanguage":tLang,"author":{"@type":"Organization","name":"all-lifes.com"},"publisher":{"@type":"Organization","name":"all-lifes.com"},"description":cDesc,"articleSection":arcanaLabel});
